    uint32_t I = x_shape->GetDim(1);
    uint32_t H = h0_shape->GetDim(1);
    // w_h2o shape: (O, H) -> first dim O, second H
    uint32_t O = w_h2o_shape->GetDim(0);

    // Compute K directly to avoid storing it
